const item = $input.first().json;
const stats = item.items?.[0]?.statistics || {};
const views = parseInt(stats.viewCount || 0);
const likes = parseInt(stats.likeCount || 0);
const comments = parseInt(stats.commentCount || 0);
const video_id = $('Video Uploaded Webhook').first().json.video_id;
const channel_id = $('Video Uploaded Webhook').first().json.channel_id;
const title = $('Video Uploaded Webhook').first().json.title;
const low_performance = views < 200;
return [{ json: { video_id, channel_id, title, views, likes, comments, low_performance, checked_at: new Date().toISOString() } }];

